 1	import * as React from 'react';
 2	import {
 3	  Button,
 4	  ButtonVariant,
 5	  TextContent,
 6	  Title,
 7	} from '@patternfly/react-core';
 8	import { useHistory } from 'react-router';
 9	import { useTranslation } from 'react-i18next';
10	import { CatalogItem } from '@openshift-console/dynamic-plugin-sdk';
11	import CatalogBadges from '../catalog/CatalogBadges';
12	import { handleCta } from './utils/quick-search-utils';
13	import { TaskSearchCallback } from '../pipeline-builder/types';
14	
15	import './QuickSearchDetails.scss';
16	
17	export type QuickSearchDetailsRendererProps = {
18	  selectedItem: CatalogItem;
19	  closeModal: () => void;
20	  namespace?: string;
21	  callback?: TaskSearchCallback;
22	  setFailedTasks?: React.Dispatch<React.SetStateAction<string[]>>;
23	};
24	export type DetailsRendererFunction = (
25	  props: QuickSearchDetailsRendererProps,
26	) => React.ReactNode;
27	export interface QuickSearchDetailsProps
28	  extends QuickSearchDetailsRendererProps {
29	  detailsRenderer: DetailsRendererFunction;
30	}
31	
32	const QuickSearchDetails: React.FC<QuickSearchDetailsProps> = ({
33	  selectedItem,
34	  closeModal,
35	  detailsRenderer,
36	  namespace,
37	  callback,
38	  setFailedTasks,
39	}) => {
40	  const { t } = useTranslation('plugin__pipelines-console-plugin');
41	  const history = useHistory();
42	  const defaultContentRenderer: DetailsRendererFunction = (
43	    props: QuickSearchDetailsProps,
44	  ): React.ReactNode => {
45	    return (
46	      <>
47	        <Title headingLevel="h4">{props.selectedItem.name}</Title>
48	        {props.selectedItem.provider && (
49	          <span className="ocs-quick-search-details__provider">
50	            {t('Provided by {{provider}}', {
51	              provider: props.selectedItem.provider,
52	            })}
53	          </span>
54	        )}
55	        {selectedItem.badges?.length > 0 ? (
56	          <CatalogBadges badges={selectedItem.badges} />
57	        ) : undefined}
58	        <Button
59	          variant={ButtonVariant.primary}
60	          className="ocs-quick-search-details__form-button"
61	          data-test="create-quick-search"
62	          onClick={(e) => {
63	            handleCta(e, props.selectedItem, props.closeModal, history);
64	          }}
65	        >
66	          {props.selectedItem.cta.label}
67	        </Button>
68	        <TextContent className="ocs-quick-search-details__description">
69	          {props.selectedItem.description}
70	        </TextContent>
71	      </>
72	    );
73	  };
74	  const detailsContentRenderer: DetailsRendererFunction =
75	    detailsRenderer ?? defaultContentRenderer;
76	
77	  return (
78	    <div className="ocs-quick-search-details">
79	      {detailsContentRenderer({
80	        selectedItem,
81	        closeModal,
82	        namespace,
83	        callback,
84	        setFailedTasks,
85	      })}
86	    </div>
87	  );
88	};
89	
90	export default QuickSearchDetails;

